mapper.select:
SELECT
    id, line_no, rule_name, rule_no, data_source_no, cond, threshold, threshold_type, result, version, deploy_at, is_valid, create_at
FROM rule


        line_no = #{param.lineNo}


        AND rule_name like CONCAT(#{param.ruleName}, '%')


        AND rule_no = #{param.ruleNo}


        AND data_source_no = #{param.dataSourceNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

LIMIT #{start}, #{limit}

SELECT COUNT(*)
FROM rule


        line_no = #{param.lineNo}


        AND rule_name like CONCAT(#{param.ruleName}, '%')


        AND rule_no = #{param.ruleNo}


        AND data_source_no = #{param.dataSourceNo}


        AND is_valid = #{param.isValid}

    AND is_delete = 0

SELECT rule_no, rule_name, data_source_no, cond, threshold, threshold_type, result, version, is_valid FROM rule WHERE rule_no IN
#{no}
AND is_delete = 0
